import math


def main() -> None:
    print(math.factorial(0))
    print(math.factorial(1))
    print(math.factorial(5))
    print(math.factorial(10))
    print(math.comb(5, 2))
    print(math.comb(10, 3))
    print(math.comb(5, 0))
    print(math.comb(5, 5))
    print(math.comb(3, 5))
    print(math.perm(5, 2))
    print(math.perm(5, 5))
    print(math.perm(5))


if __name__ == "__main__":
    main()
